class NinjaOnePublicAPI:
    """Simple client for NinjaOne Public API 2.0."""

    def __init__(self, base_url: str, token: str = None):
        self.base_url = base_url.rstrip("/")
        self.session = _VerboseSession()
        if token:
            self.session.headers.update({"Authorization": f"Bearer {token}"})

    def _auto_convert(self, data):
        """Automatically convert dicts to dataclass objects."""
        if data is None:
            return None
        
        # Handle lists
        if isinstance(data, list):
            return [self._auto_convert(item) for item in data]
        
        # Handle dicts - try to convert to dataclass
        if isinstance(data, dict):
            # Try to find a matching dataclass by checking common fields
            # This is a best-effort approach
            return DotDict(data)
        
        return data

    def list_activities(self, **kwargs) -> GetActivitiesResponse:
        """List activities"""
        url = f"{self.base_url}/v2/activities"
        response = self.session.get(url, params=kwargs)
        response.raise_for_status()
        result = response.json() if response.content else None
        return self._auto_convert(result)


    def delete_alert(self, uid: str, **kwargs) -> Any:
        """Reset alert/condition"""
        url = f"{self.base_url}/v2/alert/{uid}"
        response = self.session.delete(url, params=kwargs)
        response.raise_for_status()
        result = response.json() if response.content else None
        return self._auto_convert(result)


    def create_reset(self, uid: str, data: Dict[str, Any] = None, **kwargs) -> Any:
        """Reset alert/condition and provide custom data for activity"""
        url = f"{self.base_url}/v2/alert/{uid}/reset"
        response = self.session.post(url, json=data, params=kwargs)
        response.raise_for_status()
        result = response.json() if response.content else None
        return self._auto_convert(result)


