# =============================================================================
# Lazy Client (Bifrost Integration)
# =============================================================================


class _LazyClient:
    """
    Module-level proxy that auto-initializes from the Bifrost NinjaOne integration.
    Provides zero-config authentication — no manual token handling needed.

    Note: Client is NOT cached so token refreshes are always picked up.
    """

    _integration_name: str = "NinjaOne"

    async def _ensure_client(self) -> "NinjaOnePublicAPI":
        from bifrost import integrations

        integration = await integrations.get(self._integration_name)
        if not integration:
            raise RuntimeError(
                f"Integration '{self._integration_name}' not found. "
                "Please set it up in Settings."
            )

        if not integration.oauth or not integration.oauth.access_token:
            raise RuntimeError(
                "NinjaOne integration is missing an access token. "
                "Please complete the OAuth setup in Settings."
            )

        config = integration.config or {}
        base_url = config.get("base_url", "https://app.ninjarmm.com")

        ninja = NinjaOnePublicAPI(base_url=base_url)
        ninja.session.headers["Authorization"] = f"Bearer {integration.oauth.access_token}"
        return ninja

    def __getattr__(self, name: str):
        async def method(*args, **kwargs):
            ninja = await self._ensure_client()
            return getattr(ninja, name)(*args, **kwargs)

        return method


# =============================================================================
# Module-level API
# =============================================================================


# Module-level lazy client instance
_lazy = _LazyClient()

# Convenience alias for imports
client = _lazy


def __getattr__(name: str):
    """Enable module-level attribute access to lazy client methods."""
    return getattr(_lazy, name)